<?php namespace App\Repositories\Accounting;use App\Repositories\BaseRepository;use App\Models\Accounting\ChartOfAccount;use Illuminate\Database\Eloquent\Collection;class ChartOfAccountRepository extends BaseRepository{    public function __construct(ChartOfAccount $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCode(string $code): ?ChartOfAccount    {        return $this->query()->where('code', $code)->first();    }    public function findByName(string $name): ?ChartOfAccount    {        return $this->query()->where('name', $name)->first();    }    public function findByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function findByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function getActiveAccounts(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getParentAccounts(): Collection    {        return $this->query()->whereNull('parent_id')->get();    }    public function getChildAccounts(int $parentId): Collection    {        return $this->findByField('parent_id', $parentId);    }    public function searchAccounts(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getBankAccounts(): Collection    {        return $this->query()->where('type', 'bank')->where('is_active', true)->get();    }    public function getIncomeAccounts(): Collection    {        return $this->query()->where('type', 'income')->where('is_active', true)->get();    }    public function getExpenseAccounts(): Collection    {        return $this->query()->where('type', 'expense')->where('is_active', true)->get();    }    public function getAssetAccounts(): Collection    {        return $this->query()->where('type', 'asset')->where('is_active', true)->get();    }    public function getLiabilityAccounts(): Collection    {        return $this->query()->where('type', 'liability')->where('is_active', true)->get();    }}